import React, { useState, useEffect } from "react";

const PdfViewer = () => {
  // State variables for PDF list, selected PDF, content, and analysis result
  const [pdfList, setPdfList] = useState([]);
  const [selectedPdf, setSelectedPdf] = useState("");
  const [pdfContent, setPdfContent] = useState("");
  const [analysisResult, setAnalysisResult] = useState("");

  // Fetch the list of PDFs from the FastAPI backend
  useEffect(() => {
    const fetchPdfList = async () => {
      try {
        const response = await fetch("http://localhost:8000/pdfs");
        const data = await response.json();
        setPdfList(data.pdf_files || []);
      } catch (error) {
        console.error("Error fetching PDFs:", error);
      }
    };

    fetchPdfList();
  }, []);

  // Fetch the content of the selected PDF (if needed for other purposes)
  const handlePdfSelection = async (event) => {
    const selected = event.target.value;
    setSelectedPdf(selected);

    try {
      const response = await fetch(
        `http://localhost:8000/pdf-content?filename=${selected}`
      );
      const data = await response.json();
      setPdfContent(data.content); // Set the content of the selected PDF
    } catch (error) {
      console.error("Error fetching PDF content:", error);
    }
  };

  // Handle the "Run" button click to send the selected PDF for analysis
  const handleAnalyze = async () => {
    try {
      const response = await fetch("http://localhost:8000/analyze-section", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          pdf: selectedPdf,
          section: "summary", // You can replace this with dynamic user input if needed
          custom_prompt: "",
        }),
      });
      const data = await response.json();
      setAnalysisResult(data.content); // Set the analysis result
    } catch (error) {
      console.error("Error analyzing PDF:", error);
    }
  };

  return (
    <div className="pdf-viewer-container" style={{ display: "flex" }}>
      <div className="left-panel" style={{ flex: "1", padding: "1rem" }}>
        <h3>Select PDF:</h3>
        <select value={selectedPdf} onChange={handlePdfSelection}>
          <option value="">-- Select a PDF --</option>
          {pdfList.map((pdf) => (
            <option key={pdf} value={pdf}>
              {pdf}
            </option>
          ))}
        </select>

        <button onClick={handleAnalyze} disabled={!selectedPdf}>
          Run Analysis
        </button>
      </div>

      <div className="right-panel" style={{ flex: "3", padding: "1rem" }}>
        {selectedPdf ? (
          <object
            data={`http://localhost:8000/pdfs/${selectedPdf}`}
            type="application/pdf"
            width="100%"
            height="800px"
            style={{ border: "none" }}
          >
            <p>Unable to display PDF file.</p>
          </object>
        ) : (
          <p>Please select a PDF from the left panel.</p>
        )}

        {analysisResult && (
          <div>
            <h3>Analysis Result:</h3>
            <pre>{analysisResult}</pre>
          </div>
        )}
      </div>
    </div>
  );
};

export default PdfViewer;
